CREATE OR REPLACE FUNCTION pg_temp.sprint6_null_text(value text)
RETURNS text
LANGUAGE sql
IMMUTABLE
AS $fn$
  SELECT NULLIF(btrim(value), '')
$fn$;

CREATE OR REPLACE FUNCTION pg_temp.sprint6_int(value text)
RETURNS integer
LANGUAGE sql
IMMUTABLE
AS $fn$
  SELECT CASE WHEN NULLIF(btrim(value), '') IS NULL THEN NULL ELSE round(value::numeric)::integer END
$fn$;

CREATE OR REPLACE FUNCTION pg_temp.sprint6_numeric(value text)
RETURNS numeric
LANGUAGE sql
IMMUTABLE
AS $fn$
  SELECT CASE WHEN NULLIF(btrim(value), '') IS NULL THEN NULL ELSE value::numeric END
$fn$;

CREATE OR REPLACE FUNCTION pg_temp.sprint6_text_array(value text)
RETURNS text[]
LANGUAGE sql
IMMUTABLE
AS $fn$
  SELECT CASE
    WHEN NULLIF(btrim(value), '') IS NULL THEN NULL
    ELSE ARRAY(SELECT jsonb_array_elements_text(value::jsonb))
  END
$fn$;

CREATE TEMP TABLE sprint6_final_exercise_patch AS
SELECT
  id,
  pg_temp.sprint6_null_text(nombre) AS nombre,
  pg_temp.sprint6_text_array(aliases) AS aliases,
  lower(regexp_replace(trim(COALESCE(pg_temp.sprint6_null_text(nombre), normalized_nombre, '')), '\s+', ' ', 'g')) AS normalized_nombre,
  pg_temp.sprint6_null_text(nivel) AS nivel,
  pg_temp.sprint6_null_text(nivel_minimo) AS nivel_minimo,
  pg_temp.sprint6_null_text(grupo_muscular) AS grupo_muscular,
  pg_temp.sprint6_null_text(musculo_principal) AS musculo_principal,
  pg_temp.sprint6_text_array(musculos_secundarios) AS musculos_secundarios,
  pg_temp.sprint6_null_text(equipamiento) AS equipamiento,
  pg_temp.sprint6_text_array(equipo_requerido) AS equipo_requerido,
  pg_temp.sprint6_null_text(tipo_entrenamiento) AS tipo_entrenamiento,
  pg_temp.sprint6_null_text(patron_movimiento) AS patron_movimiento,
  pg_temp.sprint6_null_text(descripcion) AS descripcion,
  pg_temp.sprint6_text_array(instrucciones) AS instrucciones,
  pg_temp.sprint6_text_array(cues_tecnicos) AS cues_tecnicos,
  pg_temp.sprint6_text_array(errores_comunes) AS errores_comunes,
  pg_temp.sprint6_text_array(contraindicaciones) AS contraindicaciones,
  pg_temp.sprint6_text_array(sustituciones) AS sustituciones,
  pg_temp.sprint6_text_array(progresiones) AS progresiones,
  pg_temp.sprint6_text_array(regresiones) AS regresiones,
  pg_temp.sprint6_null_text(lugar) AS lugar,
  pg_temp.sprint6_null_text(objetivo) AS objetivo,
  pg_temp.sprint6_int(series_sugeridas) AS series_sugeridas,
  pg_temp.sprint6_int(repeticiones_sugeridas) AS repeticiones_sugeridas,
  pg_temp.sprint6_int(rango_reps_min) AS rango_reps_min,
  pg_temp.sprint6_int(rango_reps_max) AS rango_reps_max,
  pg_temp.sprint6_int(descanso_segundos_min) AS descanso_segundos_min,
  pg_temp.sprint6_int(descanso_segundos_max) AS descanso_segundos_max,
  pg_temp.sprint6_int(rir_recomendado) AS rir_recomendado,
  pg_temp.sprint6_int(duracion_promedio_segundos) AS duracion_promedio_segundos,
  pg_temp.sprint6_numeric(calorias_por_repeticion) AS calorias_por_repeticion,
  pg_temp.sprint6_null_text(maquina_gym) AS maquina_gym,
  pg_temp.sprint6_null_text(estado_calidad) AS estado_calidad,
  pg_temp.sprint6_null_text(needs_review_reason) AS needs_review_reason,
  row_number() OVER (PARTITION BY lower(regexp_replace(trim(COALESCE(pg_temp.sprint6_null_text(nombre), normalized_nombre, '')), '\s+', ' ', 'g')) ORDER BY id) AS duplicate_rank_in_patch
FROM sprint6_final_exercise_patch_raw
WHERE pg_temp.sprint6_null_text(nombre) IS NOT NULL;

-- Fail early if the patch itself contains duplicate normalized names.
DO $do$
DECLARE
  duplicate_count integer;
BEGIN
  SELECT count(*) INTO duplicate_count
  FROM sprint6_final_exercise_patch
  WHERE duplicate_rank_in_patch > 1;

  IF duplicate_count > 0 THEN
    RAISE EXCEPTION 'Patch CSV contains % duplicate normalized names. Fix CSV before importing.', duplicate_count;
  END IF;
END
$do$;

CREATE TEMP TABLE sprint6_final_exercise_import_plan AS
SELECT
  p.*,
  e.id AS existing_id,
  by_name.id AS duplicate_name_existing_id,
  CASE
    WHEN p.id IS NOT NULL AND e.id IS NOT NULL THEN 'update'
    WHEN p.id IS NOT NULL AND e.id IS NULL AND by_name.id IS NULL THEN 'insert'
    WHEN p.id IS NOT NULL AND e.id IS NULL AND by_name.id IS NOT NULL THEN 'ignore_duplicate_name'
    ELSE 'ignore_invalid'
  END AS import_action
FROM sprint6_final_exercise_patch p
LEFT JOIN public.exercises e ON e.id = p.id
LEFT JOIN LATERAL (
  SELECT ex.id
  FROM public.exercises ex
  WHERE lower(regexp_replace(trim(ex.nombre), '\s+', ' ', 'g')) = p.normalized_nombre
  LIMIT 1
) by_name ON true;

-- Updates: keep id, keep created_at, never modify image/video, avoid replacing critical fields with blanks.
UPDATE public.exercises e
SET
  nombre = COALESCE(p.nombre, e.nombre),
  aliases = COALESCE(p.aliases, e.aliases),
  nivel = COALESCE(p.nivel, e.nivel),
  nivel_minimo = COALESCE(p.nivel_minimo, e.nivel_minimo),
  grupo_muscular = COALESCE(p.grupo_muscular, e.grupo_muscular),
  musculo_principal = COALESCE(p.musculo_principal, e.musculo_principal),
  musculos_secundarios = COALESCE(p.musculos_secundarios, e.musculos_secundarios),
  equipamiento = COALESCE(p.equipamiento, e.equipamiento),
  equipo_requerido = COALESCE(p.equipo_requerido, e.equipo_requerido),
  tipo_entrenamiento = COALESCE(p.tipo_entrenamiento, e.tipo_entrenamiento),
  patron_movimiento = COALESCE(p.patron_movimiento, e.patron_movimiento),
  descripcion = COALESCE(p.descripcion, e.descripcion),
  instrucciones = COALESCE(p.instrucciones, e.instrucciones),
  cues_tecnicos = COALESCE(p.cues_tecnicos, e.cues_tecnicos),
  errores_comunes = COALESCE(p.errores_comunes, e.errores_comunes),
  contraindicaciones = COALESCE(p.contraindicaciones, e.contraindicaciones),
  sustituciones = COALESCE(p.sustituciones, e.sustituciones),
  progresiones = COALESCE(p.progresiones, e.progresiones),
  regresiones = COALESCE(p.regresiones, e.regresiones),
  lugar = COALESCE(p.lugar, e.lugar),
  objetivo = COALESCE(p.objetivo, e.objetivo),
  series_sugeridas = COALESCE(p.series_sugeridas, e.series_sugeridas),
  repeticiones_sugeridas = COALESCE(p.repeticiones_sugeridas, e.repeticiones_sugeridas),
  rango_reps_min = CASE WHEN COALESCE(p.tipo_entrenamiento, e.tipo_entrenamiento) ILIKE 'cardio%' THEN NULL ELSE COALESCE(p.rango_reps_min, e.rango_reps_min) END,
  rango_reps_max = CASE WHEN COALESCE(p.tipo_entrenamiento, e.tipo_entrenamiento) ILIKE 'cardio%' THEN NULL ELSE COALESCE(p.rango_reps_max, e.rango_reps_max) END,
  descanso_segundos_min = COALESCE(p.descanso_segundos_min, e.descanso_segundos_min),
  descanso_segundos_max = COALESCE(p.descanso_segundos_max, e.descanso_segundos_max),
  rir_recomendado = CASE WHEN COALESCE(p.tipo_entrenamiento, e.tipo_entrenamiento) ILIKE 'cardio%' THEN NULL ELSE COALESCE(p.rir_recomendado, e.rir_recomendado) END,
  duracion_promedio_segundos = COALESCE(p.duracion_promedio_segundos, e.duracion_promedio_segundos),
  calorias_por_repeticion = COALESCE(p.calorias_por_repeticion, e.calorias_por_repeticion),
  maquina_gym = COALESCE(p.maquina_gym, e.maquina_gym),
  estado_calidad = CASE
    WHEN p.estado_calidad IN ('legacy', 'pendiente', 'basico', 'revisar', 'curado', 'deprecado', 'premium') THEN p.estado_calidad
    ELSE e.estado_calidad
  END
FROM sprint6_final_exercise_import_plan p
WHERE p.import_action = 'update'
  AND e.id = p.existing_id;

-- Inserts: generate new UUID text ids and skip any name already present.
INSERT INTO public.exercises (
  id,
  nombre,
  aliases,
  nivel,
  nivel_minimo,
  grupo_muscular,
  musculo_principal,
  musculos_secundarios,
  equipamiento,
  equipo_requerido,
  tipo_entrenamiento,
  patron_movimiento,
  descripcion,
  instrucciones,
  cues_tecnicos,
  errores_comunes,
  contraindicaciones,
  sustituciones,
  progresiones,
  regresiones,
  lugar,
  objetivo,
  series_sugeridas,
  repeticiones_sugeridas,
  rango_reps_min,
  rango_reps_max,
  descanso_segundos_min,
  descanso_segundos_max,
  rir_recomendado,
  duracion_promedio_segundos,
  calorias_por_repeticion,
  maquina_gym,
  estado_calidad,
  imagen,
  video
)
SELECT
  gen_random_uuid()::text,
  p.nombre,
  COALESCE(p.aliases, '{}'::text[]),
  COALESCE(p.nivel, 'principiante'),
  COALESCE(p.nivel_minimo, p.nivel, 'principiante'),
  COALESCE(p.grupo_muscular, 'general'),
  p.musculo_principal,
  COALESCE(p.musculos_secundarios, '{}'::text[]),
  p.equipamiento,
  COALESCE(p.equipo_requerido, '{}'::text[]),
  COALESCE(p.tipo_entrenamiento, 'fuerza'),
  p.patron_movimiento,
  COALESCE(p.descripcion, 'Ejercicio pendiente de descripcion editorial.'),
  COALESCE(p.instrucciones, '{}'::text[]),
  COALESCE(p.cues_tecnicos, '{}'::text[]),
  COALESCE(p.errores_comunes, '{}'::text[]),
  COALESCE(p.contraindicaciones, '{}'::text[]),
  COALESCE(p.sustituciones, '{}'::text[]),
  COALESCE(p.progresiones, '{}'::text[]),
  COALESCE(p.regresiones, '{}'::text[]),
  p.lugar,
  p.objetivo,
  p.series_sugeridas,
  p.repeticiones_sugeridas,
  CASE WHEN COALESCE(p.tipo_entrenamiento, '') ILIKE 'cardio%' THEN NULL ELSE p.rango_reps_min END,
  CASE WHEN COALESCE(p.tipo_entrenamiento, '') ILIKE 'cardio%' THEN NULL ELSE p.rango_reps_max END,
  p.descanso_segundos_min,
  p.descanso_segundos_max,
  CASE WHEN COALESCE(p.tipo_entrenamiento, '') ILIKE 'cardio%' THEN NULL ELSE p.rir_recomendado END,
  p.duracion_promedio_segundos,
  p.calorias_por_repeticion,
  p.maquina_gym,
  CASE
    WHEN p.estado_calidad IN ('legacy', 'pendiente', 'basico', 'revisar', 'curado', 'deprecado', 'premium') THEN p.estado_calidad
    ELSE 'revisar'
  END,
  NULL,
  NULL
FROM sprint6_final_exercise_import_plan p
WHERE p.import_action = 'insert'
  AND NOT EXISTS (
    SELECT 1
    FROM public.exercises existing
    WHERE lower(regexp_replace(trim(existing.nombre), '\s+', ' ', 'g')) = p.normalized_nombre
  );

-- Mark explicit review/deprecation rows if a future CSV includes action semantics in estado/reason.
UPDATE public.exercises e
SET estado_calidad = 'revisar'
FROM sprint6_final_exercise_import_plan p
WHERE p.import_action = 'update'
  AND e.id = p.existing_id
  AND p.estado_calidad = 'revisar';

-- Cleanup accidental self-substitutions after import.
UPDATE public.exercises e
SET sustituciones = cleaned.items
FROM (
  SELECT
    id,
    COALESCE(array_agg(item ORDER BY first_seen) FILTER (WHERE item IS NOT NULL), '{}'::text[]) AS items
  FROM (
    SELECT
      e.id,
      s.item,
      min(s.ordinality) AS first_seen
    FROM public.exercises e
    LEFT JOIN LATERAL unnest(e.sustituciones) WITH ORDINALITY AS s(item, ordinality) ON true
    WHERE s.item IS NULL
       OR (
        lower(trim(s.item)) <> lower(trim(e.nombre))
        AND lower(trim(s.item)) <> ALL (SELECT lower(trim(alias_item)) FROM unnest(e.aliases) AS alias_item)
      )
    GROUP BY e.id, s.item
  ) deduped
  GROUP BY id
) cleaned
WHERE e.id = cleaned.id;


-- Defensive cleanup required by final validation: do not delete exercises, do not touch media, keep IDs stable.
UPDATE public.exercises
SET rango_reps_min = NULL,
    rango_reps_max = NULL,
    rir_recomendado = NULL
WHERE tipo_entrenamiento ILIKE 'cardio%'
   OR patron_movimiento ILIKE '%cardio%';

UPDATE public.exercises
SET instrucciones = CASE
  WHEN tipo_entrenamiento ILIKE 'cardio%' OR patron_movimiento ILIKE '%cardio%' THEN ARRAY[
    'Ajusta la intensidad a un ritmo sostenible antes de iniciar.',
    'Mantén postura estable y respiración controlada durante el esfuerzo.',
    'Completa el tiempo o intervalo indicado sin dolor ni mareo.',
    'Reduce la intensidad si pierdes técnica, coordinación o control.'
  ]
  ELSE ARRAY[
    'Prepara el equipo y adopta una postura estable.',
    'Ejecuta el movimiento con rango controlado y sin impulso excesivo.',
    'Mantén tensión en el músculo objetivo durante la fase principal.',
    'Regresa a la posición inicial con control antes de repetir.'
  ]
END
WHERE array_length(instrucciones, 1) IS NULL;

UPDATE public.exercises
SET descripcion = CASE
  WHEN tipo_entrenamiento ILIKE 'cardio%' OR patron_movimiento ILIKE '%cardio%' THEN
    'Actividad cardiovascular de ' || nombre || ' orientada a mejorar resistencia, capacidad aeróbica y control de intensidad. Se programa por tiempo, distancia o intervalos según el nivel del usuario.'
  ELSE
    'Ejercicio de ' || lower(coalesce(grupo_muscular, 'fuerza')) || ' enfocado en ' || coalesce(NULLIF(musculo_principal, ''), 'el músculo objetivo') || '. Prioriza técnica controlada, rango seguro y progresión gradual.'
END
WHERE descripcion IS NULL
   OR trim(descripcion) = ''
   OR descripcion ILIKE '%requiere control tecnico%'
   OR descripcion ILIKE '%requiere control técnico%'
   OR descripcion ILIKE '%Ejercicio de fuerza o habilidad%'
   OR descripcion ILIKE '%Ejercicio cardiovascular orientado a mejorar resistencia%';

UPDATE public.exercises
SET musculo_principal = COALESCE(NULLIF(musculo_principal, ''), NULLIF(grupo_muscular, ''), 'general')
WHERE musculo_principal IS NULL OR trim(musculo_principal) = '';

UPDATE public.exercises
SET equipamiento = COALESCE(NULLIF(equipamiento, ''), 'ninguno')
WHERE equipamiento IS NULL OR trim(equipamiento) = '';

UPDATE public.exercises
SET equipo_requerido = ARRAY[COALESCE(NULLIF(equipamiento, ''), 'ninguno')]
WHERE array_length(equipo_requerido, 1) IS NULL;

UPDATE public.exercises
SET rango_reps_min = COALESCE(rango_reps_min, 8),
    rango_reps_max = COALESCE(rango_reps_max, 12),
    descanso_segundos_min = COALESCE(descanso_segundos_min, 60),
    descanso_segundos_max = COALESCE(descanso_segundos_max, 90),
    rir_recomendado = COALESCE(rir_recomendado, 2)
WHERE tipo_entrenamiento NOT ILIKE 'cardio%'
  AND duracion_promedio_segundos IS NULL;
-- Runtime import report for Supabase SQL Editor.
SELECT import_action, count(*) AS rows
FROM sprint6_final_exercise_import_plan
GROUP BY import_action
ORDER BY import_action;

SELECT id, nombre, duplicate_name_existing_id AS existing_id_with_same_name
FROM sprint6_final_exercise_import_plan
WHERE import_action = 'ignore_duplicate_name'
ORDER BY nombre;

COMMIT;
